def maxCoins(nums: list[int]) -> int:
    n = len(nums)
    arr = [1] + nums + [1]

    dp = [[0] * (n + 2) for _ in range(n + 2)]

    for length in range(1, n + 1):
        for i in range(n - length + 1):
            j = i + length + 1

            for k in range(i + 1, j):
                coins = arr[i] * arr[k] * arr[j]
                coins += dp[i][k]
                coins += dp[k][j]

                dp[i][j] = max(dp[i][j], coins)

    return dp[0][n + 1]
